#include <bits/stdc++.h>
using namespace std;
int ans=0,n;
string s[57];
int vis[57]; 
void dfs(int i,int len)
{ 
	ans=max(len,ans);
	for(int j=1;j<=n;j++)
	{
		if(s[j][0]==s[i][1]&&vis[j]==0)
		{
			vis[j]=1;
			dfs(j,len+1);
			vis[j]=0;
		}	
	}	
}
int main(){
	cin>>n; 
	for(int i=1;i<=n;i++) cin>>s[i];
	vis[1]=1;
	dfs(1,1);
	cout<<ans;
}
